// ----- LOC 4 — spawnCompanion: animMap construction --------------------------
// File: game.html, REPLACE spawnCompanion(). The new version registers each
// combo sheet AND the rangedAttackSheet as their own animator entries
// (combo0, combo1, combo2, rangedAttack) so forcePlay can switch between them
// by name — no runtime texture swap.

function spawnCompanion(type, x, z) {
  const cfg = COMPANION_CFG[type];
  if (!cfg) return null;
  const sprite = makeAnimSprite(cfg.scale);
  sprite.position.set(x, cfg.baseY, z);
  scene.add(sprite);
  const shadow = makeShadow(cfg.shadowSize);
  scene.add(shadow);
  const animMap = Object.assign({}, cfg.sheets);
  if (cfg.comboSheets) {
    cfg.comboSheets.forEach((key, i) => { animMap['combo' + i] = key; });
  }
  if (cfg.rangedAttackSheet) {
    animMap['rangedAttack'] = cfg.rangedAttackSheet;
  }
  const anim = createAnimator(sprite, animMap, 'idle');
  const bar = makeCompanionHpBar(cfg.barColor, cfg.maxHp);
  scene.add(bar);
  sprite.userData = {
    type, cfg, anim, shadow, hpBar: bar,
    hp: cfg.maxHp, maxHp: cfg.maxHp,
    facing: 1,
    target: null,
    attacking: false, attackTimer: 0, attackHitDelay: 0, attackHitFired: true,
    cooldown: 0,
    knockVel: new THREE.Vector3(),
    flash: 0, dying: false,
    movedThisFrame: false,
    skirmishTimer: 0,
    comboStep: 0,
    comboResetTimer: 0,
    throwCd: 0,
    postCooldown: null,
  };
  state.companions.push(sprite);
  return sprite;
}


