// ----- LOC 6 — Ground-spear system (NEW) -------------------------------------
// File: game.html, ADD this block once near the other companion helpers (e.g.
// right after spawnFriendlyArrow or anywhere global). It defines:
//   - state.spearStrikes: array of active strikes
//   - spawnGroundSpear(): emits one strike at (x,z) targeting one enemy
//   - spawnSpearAoE(): finds N nearest enemies in radius, calls spawnGroundSpear once each
//   - updateSpearStrikes(): tick IN/OUT animations + apex damage

state.spearStrikes = [];

function spawnGroundSpear(x, z, damage, targetEnemy) {
  const inTex = makeAnimTex('spearGroundIn');
  const mat = new THREE.SpriteMaterial({
    map: inTex, transparent: true, alphaTest: 0.05, depthWrite: false,
  });
  const sprite = new THREE.Sprite(mat);
  const SCALE = 5;
  sprite.scale.set(SCALE, SCALE, 1);
  // position.y = scale/2 so frame BOTTOM sits at world y=0 (spear emerges from floor).
  sprite.position.set(x, SCALE / 2, z);
  sprite.renderOrder = 4;
  scene.add(sprite);
  state.spearStrikes.push({
    sprite, phase: 'in', elapsed: 0, hit: false,
    damage, target: targetEnemy,
  });
  if (typeof impactRing === 'function') {
    impactRing(new THREE.Vector3(x, 0.05, z), 0x88ddff, 1.6, 0.3);
  }
}

function spawnSpearAoE(centerX, centerZ, damage, radius, maxTargets) {
  const candidates = [];
  for (const e of state.enemies) {
    if (e.userData.dying) continue;
    const dx = e.position.x - centerX;
    const dz = e.position.z - centerZ;
    const d = Math.hypot(dx, dz);
    if (d < radius) candidates.push({ e, d });
  }
  if (candidates.length === 0) {
    // No targets — still play the visual at aim point (player gets feedback).
    spawnGroundSpear(centerX, centerZ, 0, null);
    return;
  }
  candidates.sort((a, b) => a.d - b.d);
  const targets = candidates.slice(0, maxTargets);
  for (const { e } of targets) {
    spawnGroundSpear(e.position.x, e.position.z, damage, e);
  }
}

function updateSpearStrikes(dt) {
  for (let i = state.spearStrikes.length - 1; i >= 0; i--) {
    const s = state.spearStrikes[i];
    s.elapsed += dt;
    if (s.phase === 'in') {
      const sheet = SHEETS.spearGroundIn;
      const animDur = sheet.n / sheet.fps;
      let f = Math.floor(s.elapsed * sheet.fps);
      if (f >= sheet.n) f = sheet.n - 1;
      const tex = s.sprite.material.map;
      tex.repeat.x = 1 / sheet.n;
      tex.offset.x = f / sheet.n;
      // Damage at apex frame (~5 of 9). Fires once per strike.
      if (!s.hit && f >= 5) {
        s.hit = true;
        const t = s.target;
        if (t && !t.userData.dying && s.damage > 0) {
          const eud = t.userData;
          eud.hp -= s.damage;
          eud.flash = 0.28;
          const dx = t.position.x - s.sprite.position.x;
          const dz = t.position.z - s.sprite.position.z;
          const len = Math.hypot(dx, dz) || 1;
          eud.knockVel.set(dx / len * 2, 0, dz / len * 2);
          burst(t.position.clone().setY(0.7), 'cyan', 10, 5, 0.32);
          state.hitStop = Math.max(state.hitStop, 0.04);
          if (typeof sfx !== 'undefined' && sfx.hit) sfx.hit(0);
          if (eud.hp <= 0 && !eud.dying) {
            eud.dying = true;
            if (typeof awardGold === 'function') awardGold(5);
            const enemy = t;
            const finishDeath = () => {
              scene.remove(enemy);
              scene.remove(eud.shadow);
              const idx = state.enemies.indexOf(enemy);
              if (idx >= 0) state.enemies.splice(idx, 1);
            };
            if (eud.anim && eud.anim.anims && eud.anim.anims.hurt) {
              eud.anim.forcePlay('hurt', () => {
                if (eud.anim.anims.death) eud.anim.forcePlay('death', finishDeath);
                else finishDeath();
              });
            } else if (eud.anim && eud.anim.anims && eud.anim.anims.death) {
              eud.anim.forcePlay('death', finishDeath);
            } else {
              finishDeath();
            }
          }
        }
      }
      if (s.elapsed >= animDur) {
        s.phase = 'out';
        s.elapsed = 0;
        s.sprite.material.map = makeAnimTex('spearGroundOut');
      }
    } else {
      const sheet = SHEETS.spearGroundOut;
      let f = Math.floor(s.elapsed * sheet.fps);
      if (f >= sheet.n) {
        scene.remove(s.sprite);
        state.spearStrikes.splice(i, 1);
        continue;
      }
      const tex = s.sprite.material.map;
      tex.repeat.x = 1 / sheet.n;
      tex.offset.x = f / sheet.n;
    }
  }
}


